proof_block:
// Pull both ensures conjuncts into the proof context under a guard that
// matches the antecedent of the determinism implication. Each conjunct
// pins the corresponding output multiset to `v@.to_multiset().filter(f_spec)`;
// chain them through Verus's extensional-equality-implies-equality axiom so
// z3 derives `r1@.to_multiset() == r2@.to_multiset()` and the matching
// length equality on the sequence views, then close the goal with the
// sequence ext-equal operator.
if (r1@.to_multiset() =~= v@.to_multiset().filter(f_spec))
    && (r2@.to_multiset() =~= v@.to_multiset().filter(f_spec)) {
    assert(r1@.to_multiset() == v@.to_multiset().filter(f_spec));
    assert(r2@.to_multiset() == v@.to_multiset().filter(f_spec));
    assert(r1@.to_multiset() == r2@.to_multiset());
    assert(r1@.to_multiset() =~= r2@.to_multiset());
    assert(r1@.len() == r1@.to_multiset().len());
    assert(r2@.len() == r2@.to_multiset().len());
    assert(r1@.len() == r2@.len());
    assert(r1@ =~= r2@);
}

